import startImage from '../assets/startpage.png';

function MainPage() {
  return (
    <div className="relative w-full h-screen overflow-hidden">
      {/* 흐릿한 전체 배경 */}
      <img
        src={startImage}
        alt="배경"
        className="absolute top-0 left-0 w-full h-full object-cover opacity-30 blur-sm -z-10"
      />

      {/* 시작 페이지 스타일 중앙 콘텐츠 */}
      <div className="flex flex-col items-center justify-between h-full py-10 px-4">
        {/* 상단 로고 */}
        <h1 className="text-3xl font-bold text-blue-600">HomeProtect</h1>

        {/* 메인 카드 내용 */}
        <div className="space-y-6 w-full max-w-2xl">
          {[
            '부동산 관련 정보 제공',
            '부동산 관련 퀴즈',
            '부동산 지원 정책',
          ].map((title, i) => (
            <div
              key={i}
              className="bg-white/80 border border-blue-200 rounded-xl p-6 flex items-center justify-between shadow hover:shadow-md transition backdrop-blur"
            >
              <span className="font-bold text-gray-800">{title}</span>
              <button className="bg-blue-600 text-white px-4 py-2 rounded-full hover:bg-blue-700">
                바로가기
              </button>
            </div>
          ))}
        </div>

        {/* 하단 로그인 또는 버튼 */}
        <div className="flex items-center gap-2 mt-10">
          <span className="text-blue-600 text-lg">→</span>
          <button className="bg-blue-600 text-white px-6 py-2 rounded-full hover:bg-blue-700 transition">
            로그인
          </button>
        </div>
      </div>
    </div>
  );
}

export default MainPage;
